<template>
    <view class="container">
        <view class="avatar" @click="toPreview">
            <u-avatar :src="info.avatar" size="120"></u-avatar>
        </view>
        <view class="shopName">[各種設定/店舗情報/店舗名]が反映される</view>
        <view class="inpContent">
            <view class="inpTitle">
                担当者(任意)
            </view>
            <view class="inp">
                <u-input v-model="name" placeholder="担当者を入力してください"></u-input>
            </view>
        </view>
        <u-button class="btn" type="primary" :plain="true" @click="save">保存</u-button>
    </view>
</template>

<script>
    let that 
    import {
        getShopInfo,
        changeChatInfo
    } from "@/api/index.js"
    export default {
        data() {
            return {
                name: "",
                show: false,
                info:{}
            }
        },
        created() {
            let that = this
            let userInfo = uni.getStorageSync("admin")
            console.log(userInfo)
            that.name = userInfo.name
            that.getUserInfo()
        },
        methods: {
            toPreview() {
                let that = this
                console.log(that.info.avatar)
                uni.navigateTo({
                    url: "preview/preview?url=" + that.info.avatar
                })
            },
            getValue(e){
                let that = this
                if(e){
                    that.info.avatar = e
                }
            },
            getUserInfo() {
                let that = this
                getShopInfo().then((res) => {
                    console.log(res)
                    if(res.code == 200){
                        that.info = res.data.shop_info
                    }
                })
            },
            save(){
                that = this
                let data = {}
                data.type = "info"
                data.name = that.name
                data.avatar = that.info.avatar
               changeChatInfo(data).then((res) => {
                   console.log(res)
                   if(res.code == 200){
                       uni.showToast({
                           title:res.message,
                           duration:2000
                       })
                       let userInfo = uni.getStorageSync("admin")
                       userInfo.name = that.name
                       uni.setStorageSync("admin",userInfo)
                       setTimeout(() => {
                           uni.navigateBack()
                       },2000)
                   }
               })
            }
        }
    }
</script>

<style lang="scss">
    .container {
        border-top: 2upx solid #d2d2d7;
        box-sizing: border-box;
        padding-top: 174upx;

        .avatar {
            margin: 0 auto;
            text-align: center;
            width: 240upx;
            height: 240upx;
            ;
        }

        .shopName {
            font-size: 32upx;
            font-family: Hiragino Sans-W6, Hiragino Sans;
            font-weight: normal;
            color: #1D1D1F;
            text-align: center;
            margin-top: 60upx;
        }

        .inpContent {
            margin-top: 100upx;

            .inpTitle {
                margin-bottom: 10upx;
            }
        }

        .btn {
            width: 480upx;
            height: 96upx;
            margin-top: 398upx;
        }
    }
</style>
